fn format_radix(mut num: i64, radix: i64) -> String {
    if num == 0 {
        return "0".to_string();
    }

    let mut chars = Vec::new();
    while num > 0 {
        let rem = num % radix;
        let c = match rem {
            0..=9 => (b'0' + rem as u8) as char,
            _ => (b'A' + (rem - 10) as u8) as char,
        };
        chars.push(c);
        num /= radix;
